arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// --- Train the model at startup ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

IDataView data = mlContext.Data.LoadFromTextFile<ChurnInput>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(ChurnInput.Age)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(ChurnInput.Income)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(ChurnInput.PurchaseHistory)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(ChurnInput.Age), nameof(ChurnInput.Income),
        nameof(ChurnInput.PurchaseHistory), "RegionEncoded"))
    .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(ChurnInput.Churned)))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"))
    .Append(mlContext.Transforms.Conversion.MapKeyToValue(
        "PredictedLabel", "PredictedLabel"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate on test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                  $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Save model for PredictionEnginePool
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);

// Register thread-safe prediction engine pool
builder.Services.AddPredictionEnginePool<ChurnInput, ChurnOutput>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => new { status = "Churn Predictor running", metrics.Accuracy, metrics.AreaUnderRocCurve });

app.MapPost("/predict", (ChurnRequest req, PredictionEnginePool<ChurnInput, ChurnOutput> pool) =>
{
    var input = new ChurnInput
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory,
    };
    var result = pool.Predict(input);
    return new
    {
        WillChurn = result.PredictedLabel,
        Probability = result.Probability,
        Score = result.Score,
    };
});

app.Run();

// --- Data models ---

public class ChurnInput
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = string.Empty;
}

public class ChurnOutput
{
    [ColumnName("PredictedLabel")]
    public string PredictedLabel { get; set; } = string.Empty;
    public float Probability { get; set; }
    public float Score { get; set; }
}

public record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

